75:     // ----------------
76:     // IR logic
77:     // ----------------
78:     logic [IrLength-1:0]  jtag_ir_shift_d, jtag_ir_shift_q; // shift register
79:     ir_reg_t              jtag_ir_d, jtag_ir_q; // IR register -> this gets captured from shift register upon update_ir
80:     logic capture_ir, shift_ir, pause_ir, update_ir;
81: 
82:     always_comb begin
83:         jtag_ir_shift_d = jtag_ir_shift_q;
84:         jtag_ir_d       = jtag_ir_q;
85: 
86:         // IR shift register
87:         if (shift_ir) begin
88:             jtag_ir_shift_d = {td_i, jtag_ir_shift_q[IrLength-1:1]};
89:         end
90: 
91:         // capture IR register
92:         if (capture_ir) begin
93:             jtag_ir_shift_d =  'b0101;
94:         end
95: 
96:         // update IR register
97:         if (update_ir) begin
98:             jtag_ir_d = ir_reg_t'(jtag_ir_shift_q);
99:         end
100: 
101:         // synchronous test-logic reset
102:         if (test_logic_reset_o) begin
103:             jtag_ir_shift_d = '0;
104:             jtag_ir_d       = IDCODE;
105:         end
106:     end
107: 
108:     always_ff @(posedge tck_i, negedge trst_ni) begin
109:         if (~trst_ni) begin
110:             jtag_ir_shift_q <= '0;
111:             jtag_ir_q       <= IDCODE;
112:         end else begin
113:             jtag_ir_shift_q <= jtag_ir_shift_d;
114:             jtag_ir_q       <= jtag_ir_d;
115:         end
116:     end
117: 
118:     // ----------------
119:     // TAP DR Regs
120:     // ----------------
121:     // - Bypass
122:     // - IDCODE
123:     // - DTM CS
124:     // Define IDCODE Value
125:     localparam IDCODE_VALUE = 32'h249511C3;
126:     // 0001             version
127:     // 0100100101010001 part number (IQ)
128:     // 00011100001      manufacturer id (flextronics)
129:     // 1                required by standard
130:     logic [31:0] idcode_d, idcode_q;
131:     logic        idcode_select;
132:     logic        bypass_select;
133:     dtmcs_t      dtmcs_d, dtmcs_q;
134:     logic        bypass_d, bypass_q;  // this is a 1-bit register
135: 
136:     assign dmi_reset_o = dtmcs_q.dmireset;
137: 
138:     always_comb begin
139:         idcode_d = idcode_q;
140:         bypass_d = bypass_q;
141:         dtmcs_d  = dtmcs_q;
142: 
143:         if (capture_dr_o) begin
144:             if (idcode_select) idcode_d = IDCODE_VALUE;
145:             if (bypass_select) bypass_d = 1'b0;
146:             if (dtmcs_select_o) begin
147:                 dtmcs_d  = '{
148:                                 zero1        : '0,
149:                                 dmihardreset : 1'b0,
150:                                 dmireset     : 1'b0,
151:                                 zero0        : '0,
152:                                 idle         : 'd1,         // 1: Enter Run-Test/Idle and leave it immediately
153:                                 dmistat      : dmi_error_i, // 0: No error, 1: Op failed, 2: too fast
154:                                 abits        : 'd7, // The size of address in dmi
155:                                 version      : 'd1  // Version described in spec version 0.13 (and later?)
156:                             };
157:             end
158:         end
159: 
160:         if (shift_dr_o) begin
161:             if (idcode_select)  idcode_d = {td_i, idcode_q[31:1]};
162:             if (bypass_select)  bypass_d = td_i;
163:             if (dtmcs_select_o) dtmcs_d  = {td_i, dtmcs_q[31:1]};
164:         end
165: 
166:         if (test_logic_reset_o) begin
167:             idcode_d = IDCODE_VALUE;
168:             bypass_d = 1'b0;
169:         end
170:     end
171: 
172:     // ----------------
173:     // Data reg select
174:     // ----------------
175:     always_comb begin
176:         dmi_access_o   = 1'b0;
177:         dtmcs_select_o = 1'b0;
178:         idcode_select  = 1'b0;
179:         bypass_select  = 1'b0;
180:         case (jtag_ir_q)
181:             BYPASS0:   bypass_select  = 1'b1;
182:             IDCODE:    idcode_select  = 1'b1;
183:             DTMCSR:    dtmcs_select_o = 1'b1;
184:             DMIACCESS: dmi_access_o   = 1'b1;
185:             BYPASS1:   bypass_select  = 1'b1;
186:             default:   bypass_select  = 1'b1;
187:         endcase
188:     end
189: 
190:     // ----------------
191:     // Output select
192:     // ----------------
193:     logic tdo_mux;
194: 
195:     always_comb begin
196:         // we are shifting out the IR register
197:         if (shift_ir) begin
198:             tdo_mux = jtag_ir_shift_q[0];
199:         // here we are shifting the DR register
200:         end else begin
201:           case (jtag_ir_q)    // synthesis parallel_case
202:             IDCODE:         tdo_mux = idcode_q[0];     // Reading ID code
203:             DTMCSR:         tdo_mux = dtmcs_q[0];
204:             DMIACCESS:      tdo_mux = dmi_tdo_i;       // Read from DMI TDO
205:             default:        tdo_mux = bypass_q;      // BYPASS instruction
206:           endcase
207:         end
208: 
209:     end
210: 
211:     // DFT
212:     logic tck_n, tck_ni;
213: 
214:     cluster_clock_inverter i_tck_inv (
215:         .clk_i ( tck_i  ),

223:         .clk_o     ( tck_n      )
224:     );
225: 
226:     // TDO changes state at negative edge of TCK
227:     always_ff @(posedge tck_n, negedge trst_ni) begin
228:         if (~trst_ni) begin
229:             td_o     <= 1'b0;
230:             tdo_oe_o <= 1'b0;
231:         end else begin
232:             td_o     <= tdo_mux;
233:             tdo_oe_o <= (shift_ir | shift_dr_o);
234:         end
235:     end
236:     // ----------------
237:     // TAP FSM
238:     // ----------------
239:     // Determination of next state; purely combinatorial
240:     always_comb begin
241:         test_logic_reset_o = 1'b0;
242: 
243:         capture_dr_o       = 1'b0;
244:         shift_dr_o         = 1'b0;
245:         update_dr_o        = 1'b0;
246: 
247:         capture_ir         = 1'b0;
248:         shift_ir           = 1'b0;
249:         pause_ir           = 1'b0;
250:         update_ir          = 1'b0;
251: 
252:         case (tap_state_q)
253:             TestLogicReset: begin
254:                 tap_state_d = (tms_i) ? TestLogicReset : RunTestIdle;
255:             end
256:             RunTestIdle: begin
257:                 tap_state_d = (tms_i) ? SelectDrScan : RunTestIdle;
258:             end
259:             // DR Path
260:             SelectDrScan: begin
261:                 tap_state_d = (tms_i) ? SelectIrScan : CaptureDr;
262:             end
263:             CaptureDr: begin
264:                 capture_dr_o = 1'b1;
